question.sql:
SELECT COUNT(*) FROM ( SELECT m1.actorid FROM imdb.movies2actors m1 JOIN imdb.movies2actors m2 ON m1.movieid = m2.movieid WHERE m1.actorid < m2.actorid GROUP BY m1.actorid, m2.actorid HAVING COUNT(*) > 10
UNION
SELECT m2.actorid FROM imdb.movies2actors m1 JOIN imdb.movies2actors m2 ON m1.movieid = m2.movieid WHERE m1.actorid < m2.actorid GROUP BY m1.actorid, m2.actorid HAVING COUNT(*) > 10) AS actor_count;


    SELECT COUNT(DISTINCT l.fid)
    FROM scenicornot.locations l
    JOIN quakes.scotquakes q ON ST_DWithin(l.geom_bng, q.geom, 100);


    SELECT AVG(spd)
    FROM trajectory.tracking
    WHERE userid = 'p3' AND spd > 0;


    SELECT ST_LENGTH(ST_MAKELINE(geom ORDER BY datetime))
    FROM trajectory.tracking
    WHERE userid = 'p3';
